export const flashcards = [
  // POLITY - 50 cards
  { q: "Which article provides the right to equality?", a: "Article 14 - provides equality before law and equal protection. Article 15 prohibits discrimination on grounds of religion, race, caste, sex, place of birth. Article 16 ensures equality in employment.", cat: "polity" },
  { q: "What is the scope of Article 12 of the Constitution?", a: "Article 12 defines 'State' to include government bodies, instrumentalities, and authorities that have statutory functions. It determines applicability of Part III (Fundamental Rights).", cat: "polity" },
  { q: "Explain the doctrine of eclipse (Article 13(2))", a: "Doctrine of eclipse means a law that violates FRs is not void ab initio but 'eclipsed' - if repeal of the conflicting FR allows the law to operate, it comes back into force. Established in Bhikaji Choudhary v State of MP.", cat: "polity" },
  { q: "What is the pith and substance doctrine?", a: "A law is judged by its substance, not form. If substance falls under exclusive jurisdiction of states but form suggests center, substance prevails. Separates legislation into true character to determine legislative competence.", cat: "polity" },
  { q: "Define colorable legislation", a: "When legislature uses constitutional power for purpose not authorized - like using treaty power (Art 253) to legislate on matters in state list. Established in R.D. Gardi v State of AP case.", cat: "polity" },
  { q: "What does Article 19(1)(a) protect?", a: "Freedom of speech and expression - includes right to propagate ideas, criticize government, journalism, artistic expression. Restrictions under 19(2): national security, public order, decency, morality, defamation, contempt.", cat: "polity" },
  { q: "Explain severability doctrine", a: "If part of law violates FR, can that part be severed? Yes, if remaining part is independent and valid. Supreme Court applies in cases like Kesavananda Bharati v State of Kerala.", cat: "polity" },
  { q: "What is the Supreme Court's jurisdiction under Article 32?", a: "Original jurisdiction for enforcement of FRs. Can issue writs of habeas corpus, mandamus, prohibition, certiorari, quo warranto. Applies to High Courts via Article 226.", cat: "polity" },
  { q: "Define harmonious construction", a: "When provisions appear conflicting, interpret to give effect to both. Example: Art 19 FRs vs Art 20-21 restrictions. Established in Maneka Gandhi v Union of India.", cat: "polity" },
  { q: "What are the key points of the Kesavananda Bharati judgment (1973)?", a: "5:4 verdict establishing basic structure doctrine - certain features of Constitution cannot be amended: sovereignty, supremacy of Constitution, secular character, federal structure, separation of powers. Struck down parts of 24th Amendment.", cat: "polity" },
  { q: "Explain the Golaknath case (1967)", a: "7:6 verdict held Fundamental Rights cannot be amended under Art 368(2). Parliament cannot abolish or abridge FRs. Overruled later by 24th Amendment (1971).", cat: "polity" },
  { q: "What did the Maneka Gandhi judgment establish?", a: "1978 judgment: 'Procedure' under Art 21 must be 'reasonable' (not just prescribed by law). Expanded scope of Art 21 to include right to live with dignity. Rejected narrow interpretation in Gopalan v State of Madras.", cat: "polity" },
  { q: "What is IR Coelho's significance in constitutional law?", a: "2007 judgment: 9th Schedule laws subject to judicial review. Constitution cannot place laws beyond judicial scrutiny. Established that Art 31B (protection of certain acts) cannot override basic structure.", cat: "polity" },
  { q: "Explain Indira Gandhi v Raj Narain case", a: "1975 judgment: Election can be cancelled on grounds of electoral malpractices but natural justice must be observed. Also established doctrine of proportionality in administrative action.", cat: "polity" },
  { q: "What did Minerva Mills establish?", a: "1980 judgment: Art 25 (to amend Constitution) is itself amendable but basic structure cannot be amended. Overruled precedent that Art 368 could be amended freely.", cat: "polity" },
  { q: "Define Vishaka guidelines", a: "1997 judgment establishing framework for sexual harassment at workplace until legislation passed. Later formalized in Sexual Harassment of Women at Workplace Act 2013. Established interim guidelines as law of the land.", cat: "polity" },
  { q: "What is SR Bommai judgment about?", a: "1994 judgment: President cannot dismiss state governments arbitrarily. Judicial review of President's satisfaction. Governor's report must be independently tested before dismissing state assemblies.", cat: "polity" },
  { q: "Explain Navtej Johar judgment (2018)", a: "Decriminalized consensual sexual acts of adults via Section 377 IPC. Read down provision to exclude consensual acts between adults. Established sexual orientation as part of identity under Art 21.", cat: "polity" },
  { q: "What is Joseph Shine judgment (2019)?", a: "Struck down adultery provision (Sec 497 IPC) as violating Art 14 (equality). Adultery cannot be sole basis of criminal prosecution. Affected family law not criminal law.", cat: "polity" },
  { q: "Explain Puttaswamy judgment (2017)", a: "Right to privacy is fundamental right under Art 21. Established privacy as core of human dignity. 9:0 bench held privacy: decisional, informational, bodily. First time explicitly recognized.", cat: "polity" },
  { q: "What are the 4 pillars of Part IV (DPSPs)?", a: "Not justiciable (Art 37) but guide state policy: (1) Social and economic justice (43-48), (2) Education (45), (3) Public health and morals (47), (4) Environmental protection (48, 48A added 1988).", cat: "polity" },
  { q: "Define Article 51A duties (Fundamental Duties)", a: "Added by 42nd Amendment (1976): 11 duties including: respect Constitution, defend sovereignty, abide by law, promote harmony, safeguard property, abjure violence, develop scientific temper, protect environment. Enforceable by law per SC.", cat: "polity" },
  { q: "What is the 42nd Amendment called?", a: "'Mini Constitution' (1976): changed 'Sovereign Democratic Republic' to 'Sovereign Socialist Secular Republic', added emergency powers, 51A duties, made amendments harder, reduced judicial review scope.", cat: "polity" },
  { q: "Explain the 44th Amendment (1978)", a: "Reversed 42nd Amendment excesses: restored 'sovereign democratic' language, made amendments easier, restored Art 31 (property rights as civil not FR), reduced emergency powers, added 51A duties.", cat: "polity" },
  { q: "What did the 73rd Amendment achieve?", a: "1992 Amendment: constitutionalized panchayati raj. Added Part IX and 11th Schedule. Mandated 3-tier system, 5-year term, mandatory SCs/STs/women reservations (1/3 for women).", cat: "polity" },
  { q: "Explain the 74th Amendment", a: "1992 Amendment: constitutionalized municipal governance. Added Part IXA and 12th Schedule. 3-tier urban local bodies, 5-year term, 1/3 women reservation, property tax power.", cat: "polity" },
  { q: "What is the 1st Amendment's significance?", a: "1951: added 9th Schedule, imposed reasonable restrictions on Art 19(1)(a) and (b) for agrarian reform, added 31A allowing land ceiling laws. Upheld Zamindari abolition.", cat: "polity" },
  { q: "What did the 24th Amendment establish?", a: "1971: gave Parliament unlimited amending power under Art 368, overruled Golaknath. Made FR amendable. Later basic structure doctrine limited this in Kesavananda.", cat: "polity" },
  { q: "Explain the 25th Amendment (1971)", a: "Limited compensation for property acquisition under Art 31 (now 300A). Made land ceiling laws constitutionally valid. Removed 'due process' checks on state action.", cat: "polity" },
  { q: "What is Article 370?", a: "Gave special status to Jammu & Kashmir: separate Constitution, flag, PM, judiciary. Removed by 35A repeal in 2019. Art 370(d) allowed President to extend Constitution to J&K.", cat: "polity" },
  { q: "Explain Article 352 (National Emergency)", a: "President can declare emergency if national security threatened (war, external aggression, armed rebellion). Parliament approval within 1 month. Can extend. Triggered suspension of FRs.", cat: "polity" },
  { q: "Define Article 356 (President's Rule)", a: "If state government breaks down, President can assume state functions. Governor's report necessary. Requires Parliamentary approval within 2 months. Can last max 3 years continuously or cumulatively.", cat: "polity" },
  { q: "What is Article 360 (Financial Emergency)?", a: "Declared when financial stability threatened. Allows President to issue directions to states. Union can recover expenses from state. Can be removed by Presidential order.", cat: "polity" },
  { q: "Explain the powers of Election Commission (Article 324)", a: "Superintends, directs, controls elections to Parliament and state legislatures. 3-member body. Can postpone elections, change constituencies, derecognize parties. Quasi-judicial authority.", cat: "polity" },
  { q: "What is CAG's role (Article 148-151)?", a: "Comptroller and Auditor General: audits all government expenditure, reports to President, submits report to Parliament. Cannot be removed except impeachment. 6-year term, independent office.", cat: "polity" },
  { q: "Define UPSC composition and term", a: "Union Public Service Commission: Chairman and members. 6-year term or age 65 whichever earlier. Conducts IAS/IFS/IPS exams, promotes civil servants, recommends appointments. Art 315-323.", cat: "polity" },
  { q: "What are Finance Commission's functions?", a: "Article 280: recommends tax distribution between Union-States, grants to states, principles for pension/salary. Constituted every 5 years. Currently 16th FC (2025-26).", cat: "polity" },
  { q: "Explain NITI Aayog's role", a: "Established 2015 replacing Planning Commission. Think tank for policy. No constitutional status. Prepares sustainable development plans, coordinates federal policies. Chaired by PM.", cat: "polity" },
  { q: "What is the GST Council composition?", a: "Article 279A: Chairman (FM), state finance ministers, Union MoC minister. Recommends tax rates, exemptions, penalties. Quorum: 1/2 members. All decisions unanimous or 3/4 majority.", cat: "polity" },
  { q: "Define the 1st Schedule (Union and States)", a: "Lists 28 states and 8 UTs. Shows distribution of territories, capital cities, merger areas. Amended through Constitutional amendments.", cat: "polity" },
  { q: "What is the 3rd Schedule (Forms of Oath)?", a: "Prescribes oaths for President, VP, Judges, Members of Parliament, state officials. Art 60, 61, 124, 164 oaths detailed.", cat: "polity" },
  { q: "Explain the 5th Schedule (Tribal Areas)", a: "Administration of tribal areas in states. Schedules Tribes, provisions for Tribal Councils. Governor's powers in tribal areas. Modified several times.", cat: "polity" },
  { q: "What is the 7th Schedule (Centre-State Powers)?", a: "Three lists: Union (97 entries), Concurrent (52 entries), State (61 entries). Determines legislative and executive jurisdiction. Union prevails in concurrent list.", cat: "polity" },
  { q: "Define the 9th Schedule", a: "Laws protected from judicial review (Art 31B). Added 1951. Contains 284+ laws including land ceiling, agrarian reform, banking, mines acts. Not absolutely protected now (IR Coelho).", cat: "polity" },
  { q: "Explain the 11th Schedule (Panchayati Raj)", a: "29 subjects for panchayats: agriculture, water, education, health, public works, social welfare, culture, sports. Added by 73rd Amendment.", cat: "polity" },
  { q: "What is the 12th Schedule (Municipal Government)?", a: "18 subjects for municipalities: water supply, sanitation, roads, urban forestry, public health, slum improvement, social welfare. Added by 74th Amendment.", cat: "polity" },
  { q: "Define Article 2 (Admission of States)", a: "Parliament can admit new territories as states. Triggered by applications. Used for admission of Punjab, Haryana, Himachal Pradesh, etc.", cat: "polity" },
  { q: "Explain Article 3 (Formation of States)", a: "Parliament can form new states, alter boundaries, change names. Can only reduce state territory by following procedure (affected state's assent optional).", cat: "polity" },
  { q: "What is the 52nd Amendment (Defection Law)?", a: "1985 Amendment: added 10th Schedule. MLA defection = disqualification. Exemptions: splits (1/3 members) or mergers (2/3 members). Government changes also trigger defection.", cat: "polity" },

  // CURRENT AFFAIRS - 50 cards
  { q: "What was India's G20 Presidency focus (2023)?", a: "India held G20 presidency in 2023 with theme 'Vasudhaiva Kutumbakam' (world is one family). Outcomes: consensus on development agenda, food security, climate resilience. New Delhi Leaders Declaration adopted.", cat: "current" },
  { q: "Explain India-BRICS relationship as of 2024", a: "India member since 2009. BRICS expanded 2023 to include UAE, Egypt, Iran, Saudi Arabia. India coordinates on development, multilateralism, alternative payment systems, De-dollarization initiatives.", cat: "current" },
  { q: "What is the status of Israel-Palestine conflict (2024-2026)?", a: "October 2023 Hamas attack triggered Israeli military response. Ongoing humanitarian crisis in Gaza. International calls for ceasefire, Two-State solution. ICC issues warrants. India balances relations with both nations.", cat: "current" },
  { q: "Summarize Russia-Ukraine war implications for India", a: "Since Feb 2022 invasion. India maintained neutrality, abstained from UN votes. Impact: food/energy security, refugee crisis, international law violations. India participated in Ukrainian grain exports through sea corridors.", cat: "current" },
  { q: "What are COP28 outcomes (Dubai 2023)?", a: "First agreement on 'loss and loss fund' for climate-vulnerable countries. Operationalized 50 billion USD Fund for LDCs. UAE Consensus on transitioning away from fossil fuels. India played key role.", cat: "current" },
  { q: "Explain RBI's recent monetary policy stance", a: "RBI maintained restrictive stance 2023-2024. Repo rate stabilized 6.5%. Focused on controlling inflation while supporting growth. CRR increased to 4.5% in May 2023 to absorb liquidity.", cat: "current" },
  { q: "What is India's Union Budget 2024-25 focus?", a: "Interim budget Feb 2024: 1.5 lakh cr allocation. Full budget mid-2024: focus on infrastructure, education, green energy. Increased CAPEX allocation. Tax rationalizations announced.", cat: "current" },
  { q: "Summarize 2024 General Elections outcomes", a: "18th Lok Sabha elections: NDA-II government formed. BJP won 240 seats (down from 303). NDA 293, INDIA bloc strong opposition. Coalition government formed May 2024.", cat: "current" },
  { q: "What is the QUAD partnership?", a: "Quadrilateral Security Dialogue: India, USA, Japan, Australia. Formed 2007, formalized 2017. Focus: Indo-Pacific stability, freedom of navigation, democratic values. Annual summits conducted.", cat: "current" },
  { q: "Explain AUKUS partnership", a: "Australia-UK-USA defense alliance 2021. Provides Australia nuclear submarines. India engaged with QUAD but not AUKUS. Strategic partnership outside but complementary.", cat: "current" },
  { q: "What is India's SCO membership benefit?", a: "Shanghai Cooperation Organization since 2017. Members: 10 states. Focus: counter-terrorism, energy security, regional stability. Trade worth USD 350 billion+. India conducts defense exercises.", cat: "current" },
  { q: "Summarize the 2024 Paris Olympics outcomes", a: "India won 6 medals (1 gold, 5 silver). Major achievements in shooting, wrestling, badminton. Training program reforms discussed for future Olympics.", cat: "current" },
  { q: "What is the status of Cryptocurrency in India 2024?", a: "No dedicated law yet. RBI discourages use, restrictions on banks dealing crypto. Taxation: personal transactions taxed 30%. Blockchain technology encouraged but crypto remains unregulated.", cat: "current" },
  { q: "Explain AI regulation efforts in India", a: "2024: AI cannot be completely banned but needs regulation. Responsible AI framework being developed. Data protection via DPDP Act 2023 crucial. Industry self-regulation encouraged.", cat: "current" },
  { q: "What is India's space program milestone (2023-2024)?", a: "Chandrayaan-3: successfully landed on moon's south pole Aug 2023. Proved lander/rover capability. Aditya-L1: solar mission launched, reached Lagrange point 2024. ISRO budget increased significantly.", cat: "current" },
  { q: "Summarize recent Supreme Court judgments on privacy", a: "2023-2024: upheld privacy in LGBTQ+ rights, data protection. Puttaswamy doctrine applied to digital age. Facial recognition judgment: NCRB guidelines issued for safety.", cat: "current" },
  { q: "What is the National Monetization Pipeline (NMP)?", a: "Government initiative 2021: monetize unused government assets. Target 6 lakh cr over 4 years. Includes highways, airports, power lines. PPP model used for monetization.", cat: "current" },
  { q: "Explain PLI Scheme expansions (2023-2024)", a: "Production Linked Incentive: expanded to 14+ sectors from electronics to pharma. Target: 340 billion USD production, 350k jobs. Major beneficiaries: Apple, Samsung, BYD.", cat: "current" },
  { q: "What is the status of Agniveers recruitment?", a: "Agnipath scheme launched 2022: 4-year military service. 75% phase-out, 25% permanent commission. 18,000 recruited in 2023 cohort. Youth unemployment measure.", cat: "current" },
  { q: "Summarize Recent CAA-NRC developments", a: "CAA 2019: grants citizenship to religious minorities (except Muslims) from Pakistan, Bangladesh, Afghanistan. NRC: implementation stalled. Supreme Court monitoring continues.", cat: "current" },
  { q: "Explain India's renewable energy targets", a: "500 GW renewable capacity by 2030. Solar: 300 GW, Wind: 140 GW, Others: 60 GW. 2023: 180 GW installed, fastest expansion globally. Battery storage crucial.", cat: "current" },
  { q: "What is the status of Uniform Civil Code (UCC)?", a: "Proposed for national implementation. Uttarakhand passed 2024 UCC. Kerala, Goa, MP considering. Focus: marriage, divorce, succession. Opposition from religious minorities, federalism concerns.", cat: "current" },
  { q: "Summarize India's housing initiatives (2024)", a: "Pradhan Mantri Awas Yojana: 12+ million homes targeted. Subsidy for low-income. Health index: 60 lakh homes with water, electricity added 2023-24.", cat: "current" },
  { q: "What are recent education reforms?", a: "NEP 2020: emphasis on STEM, vocational training. Multilingual education encouraged. Common entrance exams rationalized. Teacher recruitment reforms ongoing.", cat: "current" },
  { q: "Explain India's healthcare expansion", a: "Ayushman Bharat: 50+ crore population covered. Digital health records via ABHA. Telemedicine expansion. COVID-19 vaccine drive continuous. Health spending increased.", cat: "current" },
  { q: "What is the status of IPC to BNS transition?", a: "Bharatiya Nyaya Sanhita 2023 replaces IPC: more progressive. Sections renumbered, new provisions for dignity. Implementation 2024: training programs for courts, police underway.", cat: "current" },
  { q: "Summarize CrPC to BNSS changes", a: "Bharatiya Nyaya Sanhita (Criminal) 2023: faster trial procedures, e-filing provisions, victim centric. Implemented 2024: special focus on heinous crimes, witness protection.", cat: "current" },
  { q: "What is India's position on ICC recent judgments?", a: "India not ICC member (not ratified Rome Statute). Criticized ICC warrants (Netanyahu, Putin). Concern: politicization of justice. Preference for multilateral approaches.", cat: "current" },
  { q: "Explain India's stance on climate finance", a: "Developing nation: demands climate finance commitments. COP28: negotiated loss and damage fund. Position: historical emitters (developed nations) must pay. Net-zero by 2070 target set.", cat: "current" },
  { q: "What is the status of India-China border dispute?", a: "LAC tensions ongoing since 2020. Recent clashes in Arunachal Pradesh (2023). India increased defense spending. Diplomatic dialogue channels maintained. Trade relations strained.", cat: "current" },
  { q: "Summarize recent appointments to key posts (2024)", a: "New Chief Justice of India, Election Commissioner, CAG, RBI Governor appointed. Constitutional rotation followed. Independence and impartiality emphasized.", cat: "current" },
  { q: "What is the status of Gender Justice reforms?", a: "Bharatiya Nyaya Sanhita: enhanced provisions for women. Death penalty for rape suggested. Vishaka guidelines implementation monitored. Workplace harassment prevention emphasized.", cat: "current" },
  { q: "Explain India's cybersecurity initiatives (2024)", a: "National Cybersecurity Strategy: focus on citizen protection, critical infrastructure. Digital forensics labs expanded. Cyber Swachhata Kendra for malware removal. Incident response framework.", cat: "current" },
  { q: "What are recent developments in labor laws?", a: "4 labor codes implemented: Wages, Social Security, Occupational Safety, Industrial Relations. Gig worker protections increased. E-shram registration 300+ million workers.", cat: "current" },
  { q: "Summarize India's Infrastructure Development focus", a: "National Infrastructure Pipeline: 111 lakh cr investments. PM Gati Shakti: multimodal connectivity framework. Metro expansion in 50+ cities. High-speed rail corridors planned.", cat: "current" },
  { q: "What is the status of Foreign Direct Investment (FDI)?", a: "2023-24: FDI inflows 71 billion USD (sharp decline from 85B in 2022). Concerns over tax incentives removal. Key sectors: IT, telecom, manufacturing. Strategic sectors restricted.", cat: "current" },
  { q: "Explain recent changes to Tax laws in India", a: "2024: removal of angel tax exemptions for startups. Standard deduction increased. TCS on foreign remittances. GST rate rationalization ongoing. Corporate tax competitiveness maintained.", cat: "current" },
  { q: "What is the Semiconductor Mission impact?", a: "Government investment 76,000 cr. Target: domestic chip manufacturing. Micron, IBM foundries in talks. Self-reliance in electronics crucial for security.", cat: "current" },
  { q: "Summarize recent environmental court cases (2024)", a: "NGT orders: polluting industries closure, fly ash utilization mandated. Amazon-related cases: deforestation halted in some areas. Wildlife protection cases: elephant corridor protection, tiger reserve expansion.", cat: "current" },
  { q: "What is India's stance on World Trade?", a: "WTO member: participates actively. Objections to agricultural subsidies in developed nations. Support for TRIPS waiver for medicines. Development agenda advocacy.", cat: "current" },
  { q: "Explain the status of e-governance in India", a: "DigiLocker: 300+ million users. Aadhar-based digital identity linking. Online court filing systems operational. Tax filing digitized. Digital divide narrowing gradually.", cat: "current" },
  { q: "What are India's Recent awards and recognitions?", a: "2024: UNESCO World Heritage sites expanded. Global Innovation Index: India ranks 40th. HDI improvements. Climate action recognition. Cultural heritage preservation emphasized.", cat: "current" },

  // LEGAL - 50 cards
  { q: "What is Section 2 of the Indian Penal Code (BNS)?", a: "Definitions: 'Act', 'Culpable homicide', 'Grievous hurt', 'Simple hurt', 'Wrongful gain', 'Criminal breach of trust'. Renamed as BNS 2023 with updated definitions.", cat: "legal" },
  { q: "Explain Sections 299-304 IPC (Homicide)", a: "299: Culpable homicide (death without criminal intention). 300: Murder (with intention/knowledge). 301: Abetment of suicide. 302: Murder punishment (life/death). 304: Negligent death.", cat: "legal" },
  { q: "Define Section 307 IPC (Attempt to Murder)", a: "Whoever does act with intent to cause death, knowing act likely to cause death. Punishment: up to life imprisonment. Section 308: attempt causing grievous injury.", cat: "legal" },
  { q: "What is Section 375 IPC (Rape)?", a: "Penetrative sexual assault. Absence of consent key. Punishment: 7-10 years minimum (2 years if consent but under 18). BNS 2023 broadens definition to include non-penetrative acts (sexual assault).", cat: "legal" },
  { q: "Explain Section 376 IPC variations", a: "376A: Rape by person in authority. 376B: Rape by public servant. 376C: Rape by employee of hospital/custodian. 376D: Gang rape (20 years minimum). Enhanced punishments for aggravated versions.", cat: "legal" },
  { q: "Define Section 498A IPC (Dowry Death)", a: "Cruelty to wife by husband/in-laws for dowry. Punishment: up to 3 years imprisonment. Non-bailable, cognizable. Prevention of Cruelty Act 1961 also applies.", cat: "legal" },
  { q: "What is Section 377 IPC?", a: "Criminalized consensual sexual acts by adults. Partially struck down Navtej Johar 2018 - decriminalized consensual adult acts. Section still valid for non-consensual acts, animals, children.", cat: "legal" },
  { q: "Explain Sections 420-424 IPC (Cheating)", a: "420: Cheating (dishonest inducement). 421: Conspiracy to defraud. 422: Cheating with intent to cause wrongful loss. 423: Cheating with public servant. Punishments range 6 months-7 years.", cat: "legal" },
  { q: "Define Section 188 IPC (Disobedience)", a: "Disobedience to order duly promulgated by public servant. Punishment: 6 months/250 rupees. Used against curfew violations, lockdown breaches.", cat: "legal" },
  { q: "What are Sections 351-358 IPC (Assault)?", a: "351: Assault definition (intentional act causing fear injury). 352: Simple assault. 353: Assault on officer. 354: Sexual assault. 355: Wrongful restraint. 358: Insult by gesture.", cat: "legal" },
  { q: "Explain Section 493 IPC (Bigamy)", a: "Having spouse alive, marrying again. Punishment: 7 years imprisonment. Exception: if first marriage presumed dead, marriage is per force. Applies to Hindus, Christians, Muslims.", cat: "legal" },
  { q: "Define Sections 509 IPC (Insulting Modesty)", a: "Words, sounds, gestures, acts intended to be seen intending to insult woman's modesty. Punishment: 3 years maximum. Section 509 often misused - SC issued guidelines (Yogesh Sharma).", cat: "legal" },
  { q: "What is Section 406 IPC (Criminal Breach of Trust)?", a: "Whoever entrusted with property in capacity, dishonestly misappropriates. Punishment: 3-7 years. Section 405 is simpler breach. 409: by public servant (harsher).", cat: "legal" },
  { q: "Explain Section 494 IPC (Bigamy)", a: "After marriage, husband/wife marries again during life of other (marriage valid). Punishment: 7 years imprisonment. Exceptions: if first spouse absent 7 years, death presumed.", cat: "legal" },
  { q: "Define the Indian Evidence Act Sections", a: "Section 3: relevant facts. Section 5: admissibility. Section 8: facts in issue. Section 11: facts showing relationship. Section 14: facts forming part of same transaction. Sections 25-29: confessions.", cat: "legal" },
  { q: "What is Section 141-142 IPC (Unlawful Assembly)?", a: "Section 141: assembly of 5+ with common object to commit offense. Section 142: power to disperse. Punishment under 143-145. 144 Penal Code: unlawful assembly", cat: "legal" },
  { q: "Explain Section 153 IPC (Promoting enmity)", a: "Acts promoting feeling of enmity between groups on grounds of religion, race, place, language. Punishment: 1-3 years. Section 154: owner allowing assembly knowingly.", cat: "legal" },
  { q: "Define Section 295-298 IPC (Religion)", a: "295: Injuring place of worship. 296: Disturbing religious assembly. 297: Trespassing burial. 298: Uttering words insulting religion. Punishments: 1-3 years.", cat: "legal" },
  { q: "What is Section 120A IPC (Criminal Conspiracy)?", a: "Agreement to do illegal act. Section 120B: punishment. Punishment: 6 months-5 years. Overt act required for conviction (Balkrishan case).", cat: "legal" },
  { q: "Explain Contract Act Sections 10-22 (Consideration)", a: "10: Consideration definition (something valuable in law). 14: Free consent meaning. 15-22: Coercion (Sec 15), Undue influence (Sec 16), Fraud (Sec 17), Misrepresentation (Sec 18), etc.", cat: "legal" },
  { q: "What is Section 56 Contract Act?", a: "Agreement to do impossible act is void. If after contract act becomes impossible without default, contractee cannot demand performance but gets money back.", cat: "legal" },
  { q: "Define Sections 73-75 (Damages)", a: "73: Ordinary damages. 74: Remote damages when reasonably foreseeable. 75: Stipulated damages reasonable/unreasonable. Liquidated damages enforceable, penalty not (Hadley rule).", cat: "legal" },
  { q: "Explain Negligence in Tort Law", a: "Donoghue v Stevenson test: duty of care, breach, causation, damage. Neighbour principle: owe duty to reasonable foreseen persons. SC: reasonable standard.", cat: "legal" },
  { q: "What is Strict Liability in Torts?", a: "Defendant liable without fault/negligence. Rylands v Fletcher: non-natural use of land causing escape of dangerous thing. Applied to hazardous industries, animals, defective products.", cat: "legal" },
  { q: "Define Vicarious Liability", a: "Master liable for servant's wrongful act if done in course employment. Independent contractor exception. Applied: employer-employee relationships. Breach of statutory duty triggers liability.", cat: "legal" },
  { q: "Explain Nuisance (Public and Private)", a: "Private: unlawful interference with another's land/person. Balancing test: utility vs discomfort. Public: affects community. Damages: injunction, abatement, compensation.", cat: "legal" },
  { q: "What is Defamation?", a: "False statement damaging reputation. Elements: publication, identifying plaintiff, injurious meaning, damages. Truth is defense. Privilege: fair comment, judicial proceeding. SC: defamation hurt feelings.", cat: "legal" },
  { q: "Define Trespass in Tort Law", a: "Unauthorized entry on another's land. No damage required. Types: direct physical entry, continuation of trespass, throwing things on land. Remedy: injunction, damages.", cat: "legal" },
  { q: "Explain Section 23 Contract Act (Unlawful Consideration)", a: "Consideration unlawful if forbidden by law, defeats object of law, fraudulent, causes injury to person/property, immoral/opposed to public policy. Entire contract void.", cat: "legal" },
  { q: "What is Section 25 Contract Act (Agreements without Consideration)?", a: "Generally agreements need consideration. Exceptions: gift (completed), payment of debt, promises to compensate, past services if understood as gift. Sections 25-27 detail.", cat: "legal" },
  { q: "Define CrPC Section 2 (Application)", a: "CrPC applies to investigation, prosecution, adjudication of offenses. Exceptions: military, maritime law. BNSS 2023 replaces: faster procedures, e-filing, victim centric.", cat: "legal" },
  { q: "Explain CrPC Sections 161-173 (Investigation)", a: "161: Police examination of witnesses. 162: Statements not recordable. 164: Judicial custody examination. 171: Forwarding charge sheet. Investigation timeline: strict 90-180 days.", cat: "legal" },
  { q: "What is CrPC Section 41 (Arrest without Warrant)?", a: "Police can arrest without warrant if cognizable offense, suspects flight, tampering with evidence. Arrest must be lawful, not arbitrary. SC guidelines for arrest procedure (Maneka Gandhi).", cat: "legal" },
  { q: "Define CrPC Section 97 (Arrest by Private Person)", a: "Non-police can arrest if cognizable offense committed in their presence. Must immediately hd over to police. Limited power, strict liability for false arrest.", cat: "legal" },
  { q: "Explain Indian Evidence Act Section 32-51 (Hearsay)", a: "Hearsay generally inadmissible. Exceptions: statements in documents (32), dying declaration (32), state of mind (34), reputation. Res gestae: statements accompanying act (33).", cat: "legal" },
  { q: "What is Section 101-110 Evidence Act (Burden of Proof)?", a: "101: Burden of proof. 102-104: Circumstances presuming burden. 105: Burden on accused for exceptions. 110: Burden for impossibility of proof. Criminal: beyond reasonable doubt.", cat: "legal" },
  { q: "Define Burden and Standard of Proof", a: "Criminal: 'beyond reasonable doubt' (high standard). Civil: 'preponderance of probabilities' (balance of probability). Administrative: stricter than civil, less than criminal.", cat: "legal" },
  { q: "Explain Section 133 Evidence Act (Expert Opinion)", a: "Expert opinion admissible on scientific, technical, professional matters. Basis: observation, reports, hypotheticals. Bound by facts agreed. Expert cannot state opinion on legal conclusions.", cat: "legal" },
  { q: "What is Section 113 Evidence Act (Presumption)?", a: "Discretionary presumption from facts proved. 113A: rape presumption if recent intercourse. 113B: intercourse within 2 years of marriage presumed. Creates burden on accused.", cat: "legal" },
  { q: "Define Section 52-57 Evidence Act (Relevance Exceptions)", a: "Irrelevant evidence still admitted in certain circumstances. Character, reputation, opinion of previous conduct relevant in limited situations (52-57).", cat: "legal" },
  { q: "Explain Family Law Basics (Hindu Marriage Act)", a: "Marriage solemnized before authorized person. Conditions: capacity, consent, single, not related. Valid ceremonies: girl above 18, boy 21. Divorce: mutual/contested. Maintenance: spouse/children.", cat: "legal" },
  { q: "What is the Indian Succession Act Key Provisions?", a: "Intestate succession: property transferred per will/law. Hindu succession: daughter equal to son (amended 1956). Muslim: Quranic shares. Probate, letters of administration issued by court.", cat: "legal" },
  { q: "Define Constitutional Torts", a: "Violation of fundamental rights by state. Damages available under Article 32 (SC), 226 (HC). Writ petitions for compensation. No immunity for unconstitutional acts (Olga Tellis judgment).", cat: "legal" },
  { q: "Explain Procedural Due Process", a: "State action must follow procedure prescribed by law. Procedure must be 'reasonable' (Maneka Gandhi), not arbitrary. Natural justice: audi alteram partem, nemo judex.", cat: "legal" },
  { q: "What is Substantive Due Process?", a: "Not just procedure but substance of law must be fair, reasonable, not arbitrary. Applied to strike down unjust laws. Indian courts apply sparingly compared to USA.", cat: "legal" },
  { q: "Define Administrative Law Principles", a: "Separation of powers, natural justice, reasonableness, proportionality. Wednesbury unreasonableness test. Duty of care and good faith required. Judicial review available for administrative decisions.", cat: "legal" },
  { q: "Explain Doctrine of Eclipse in Statutes", a: "If statute held unconstitutional, it becomes 'eclipsed'. If amendment removes constitutional infirmity, statute revives. Not permanently dead. Applied in Article 13 analysis.", cat: "legal" },
  { q: "What is Unjust Enrichment in Tort Law?", a: "Person receiving benefit without legal justification. Restitution remedy: unjust enrichment reversed. Quasi-contract principle. Not technically tort but equitable remedy available.", cat: "legal" },

  // ECONOMY - 45 cards
  { q: "What is Repo Rate?", a: "Rate at which RBI lends to banks against securities. Reverse Repo: rate at which RBI borrows. June 2024: Repo at 6.5% (held). Used for liquidity management, inflation control.", cat: "economy" },
  { q: "Explain CRR and SLR", a: "CRR (Cash Reserve Ratio): percentage of deposits banks must hold with RBI. May 2023: 4.5%. SLR (Statutory Liquidity Ratio): percentage in approved securities. May 2023: 18%. Control money supply.", cat: "economy" },
  { q: "What is MSF (Marginal Standing Facility)?", a: "Emergency borrowing by banks from RBI at penalty rate. 1% above Repo rate (7.5% currently). Last resort for liquidity crunch. Fixed daily limit per bank.", cat: "economy" },
  { q: "Define LAF (Liquidity Adjustment Facility)", a: "Repo and Reverse Repo mechanisms for short-term liquidity. Daily auctions. Corridor: Reverse Repo (floor) to MSF (ceiling). Maintains system liquidity, inflation control.", cat: "economy" },
  { q: "What is Open Market Operations (OMO)?", a: "RBI buying/selling securities in open market. Increases/decreases money supply. 2024: OMO used to manage excess liquidity post GST collections.", cat: "economy" },
  { q: "Explain India's Banking Structure", a: "Central bank: RBI. Scheduled commercial banks: 27 PSU, 23 private. Regional rural banks, cooperative banks. New entrants: payment banks, small finance banks. Deposit insurance: 5 lakh cap.", cat: "economy" },
  { q: "What is NBFC (Non-Banking Finance Company)?", a: "Accepts deposits, provides loans but not a bank. Less regulated. Deposits above 5 cr. Assets: 500 cr-5000 cr. Regulated by RBI. Examples: HDFC, ICICI Finance.", cat: "economy" },
  { q: "Define SFB (Small Finance Bank)", a: "New category post 2015: lend to micro-small enterprises, low-income households. Minimum capital 100 cr. 75% lending to priority sector. Examples: AU SFB, Ujjivan SFB.", cat: "economy" },
  { q: "Explain Payment Banks", a: "Introduced 2015: issue debit cards, accept deposits (1 lakh cap), provide payment services. Cannot lend. Examples: Airtel Payments, Paytm Payments. Tech-enabled financial inclusion.", cat: "economy" },
  { q: "What is MUDRA Loan Scheme?", a: "Pradhan Mantri Micro Units Development Refinance Agency: loans up to 10 lakh for micro-enterprises. Shishu (50k), Kishore (50-500k), Tarun (500k-10lakh). Interest: 8-10%.", cat: "economy" },
  { q: "Explain Fiscal Deficit vs Budget Deficit", a: "Fiscal deficit: difference between spending and revenue. Budget deficit: government spending exceeds income. Fiscal deficit = Budget deficit + net borrowing. FRBM Act: 3% target.", cat: "economy" },
  { q: "What is the FRBM Act (Fiscal Responsibility & Budget Management)?", a: "2003 Act: targets fiscal deficit 3%, revenue deficit 1.5%. 2018 amendment: replaced with fiscal deficit target, revenue deficit flexible. Current: fiscal deficit above 6% due to COVID.", cat: "economy" },
  { q: "Define Capital Deficit", a: "Government capital spending > capital receipts. Occurs when government invests more than income from asset sales. Different from fiscal deficit which includes all spending.", cat: "economy" },
  { q: "Explain GST (Goods and Services Tax)", a: "2017 implementation: Central + State component. Rates: 5, 12, 18, 28%. Subsumed 17 old taxes. Input tax credit allowed. GST Council: 22 members, unanimous decisions. Collections: 2 lakh cr monthly (2024).", cat: "economy" },
  { q: "What is Balance of Payments (BoP)?", a: "Current account (trade, services, income, transfers) + Capital account (investment, loans). Current account deficit: imports > exports. 2023-24: CAD 1.3% of GDP.", cat: "economy" },
  { q: "Explain CAD (Current Account Deficit)", a: "When imports exceed exports + net income. Financed by capital inflows. High CAD: inflation, currency pressure. India's structural CAD related to oil imports, capital goods.", cat: "economy" },
  { q: "What is FDI vs FPI?", a: "FDI: Foreign Direct Investment (long-term, control). FPI: Foreign Portfolio Investment (short-term, stocks/bonds). FDI stable, FPI volatile. 2024: FDI 71 billion USD, FPI outflows.", cat: "economy" },
  { q: "Explain Remittance Economy", a: "Non-Resident Indians send money (2023: 120 billion USD). Crucial for BoP. Fluctuates with oil prices, global economy. Skill-based remittances (IT, medical) significant.", cat: "economy" },
  { q: "What is the IMF?", a: "International Monetary Fund: 190 members. Promotes monetary cooperation, financial stability. Provides loans with conditions (structural adjustment). Articles of Agreement govern operations.", cat: "economy" },
  { q: "Explain World Bank Groups", a: "IBRD: loans to developing countries. IDA: credits to poorest nations. IFC: private sector investment. MIGA: investment insurance. Governance: weighted voting by contribution.", cat: "economy" },
  { q: "What is ADB (Asian Development Bank)?", a: "56 members: promotes development in Asia-Pacific. Loans, grants, technical assistance. HQ: Manila. India significant borrower historically (now declining due to growth).", cat: "economy" },
  { q: "Define NDB (New Development Bank)", a: "BRICS bank established 2015: infrastructure finance alternative to World Bank. Member: Brazil, Russia, India, China, South Africa. HQ: Shanghai. Lending in local currency.", cat: "economy" },
  { q: "Explain AIIB (Asian Infrastructure Investment Bank)", a: "57 members: China-led alternative to World Bank. Founded 2015. Infrastructure focus in Asia. India significant shareholder. Governance: transparent, professional standards.", cat: "economy" },
  { q: "What is CPI (Consumer Price Index)?", a: "Measures retail inflation: basket of goods/services. Base 2012=100. May 2024: 4.75%. Published monthly. Different from WPI (wholesale).", cat: "economy" },
  { q: "Explain WPI (Wholesale Price Index)", a: "Measures inflation at wholesale level. May 2024: 3.3%. Less relevant now after base effect changes. Food, fuel, manufactured goods components.", cat: "economy" },
  { q: "What is GDP and GNP?", a: "GDP: value of goods/services produced in territory. GNP: income of nationals. India 2024: GDP 3.4-3.8% growth. Per capita GDP: 2400 USD (nominal).", cat: "economy" },
  { q: "Define HDI (Human Development Index)", a: "UN measure: life expectancy, education, income. India rank: 135/191 (2023). Focuses beyond GDP: health, literacy, living standards.", cat: "economy" },
  { q: "Explain Inflation Targeting by RBI", a: "RBI target: 4% +/- 2% (6% band). Measured by CPI. 2023-24: inflation above target, restrictive policy. Flexible inflation targeting: balances price stability vs growth.", cat: "economy" },
  { q: "What is Monetary Policy Transmission?", a: "RBI policy rate changes affect lending rates, investment, consumption. Long lag (6-18 months). 2024: transmission weak due to deposit rate stickiness.", cat: "economy" },
  { q: "Explain WTO (World Trde Organization)", a: "164 members: promotes free trade. Dispute resolution mechanism. India: significant member, TRIPS waiver advocate, agricultural sector champion. Consensus decision-making.", cat: "economy" },
  { q: "What is MFN (Most Favored Nation)?", a: "WTO principle: non-discriminatory trade access. If grant privilege to one nation, extend to all WTO members. Exceptions: customs unions, least developed countries.", cat: "economy" },
  { q: "Define Protectionism vs Free Trade", a: "Protectionism: tariffs, quotas, subsidies to protect local industry. India uses infant industry argument. Free trade: removes barriers. India moving gradually towards liberalization.", cat: "economy" },
  { q: "Explain PLI Scheme (Production-Linked Incentive)", a: "2021 scheme: incentivize domestic manufacturing. 14+ sectors: electronics, pharma, auto, textiles. Target: 340 billion USD production, 350k jobs by 2025.", cat: "economy" },
  { q: "What is MGNREGA?", a: "Mahatma Gandhi National Rural Employment Guarantee Act 2005: guarantees 100 days work to rural laborers. Wages: 200-300 rupees daily. Employment expansion during downturn.", cat: "economy" },
  { q: "Explain Direct Benefit Transfer (DBT)", a: "Subsidy/benefits directly to beneficiary account via Aadhaar. Reduces leakage, ensures targeting. 2024: 100+ schemes under DBT umbrella.", cat: "economy" },
  { q: "What is Inclusive Growth?", a: "Growth benefiting all sections: rural, urban, poor, marginalized. India's 11th, 12th Five Year Plans emphasized. Requires investment in education, health, employment.", cat: "economy" },
  { q: "Explain Equitable Development", a: "Reducing regional disparities, income inequality. NITI Aayog indices measure state development. Aspiration districts program targets backward regions.", cat: "economy" },
  { q: "What is Sustainable Development?", a: "Economic growth without depleting resources. India's 2030 targets: renewable energy, poverty reduction, education, health. SDG index: India rank 112/166.", cat: "economy" },
  { q: "Explain Subsidy System in India", a: "Food subsidy: 600-700 billion. Fertilizer: 100+ billion. Fuel: fluctuates. Total fiscal burden 2-3% GDP. Targeting efficiency increases.", cat: "economy" },
  { q: "What is the Insurance Sector?", a: "Life insurance: LIC monopoly until 1999, now 16 players. Non-life: 28 insurers. Health insurance: critical post-COVID. IRDA regulates. Penetration: 2.7% life, 0.6% non-life.", cat: "economy" },
  { q: "Explain Pension System Reform", a: "National Pension System (NPS) 2004: voluntary for private sector. Defined contribution vs government pension. Pension penetration low (10%). Reform push for inclusion.", cat: "economy" },
  { q: "What is Microfinance in India?", a: "Self-help groups, NBFC-MFIs provide small loans. Focus: women, rural. Assets: 400+ billion. Overlap with MUDRA. Regulatory challenges: overindebtedness concerns.", cat: "economy" },
  { q: "Explain Labour Force Participation", a: "India's LFP: 51-55% (low due to women, youth). Unemployment: 4-6%. Underemployment significant. Skill mismatch critical. Employment crisis post-COVID ongoing.", cat: "economy" },

  // ENVIRONMENT - 40 cards
  { q: "What is the Environmental Protection Act (EPA) 1986?", a: "Central statute: protection/improvement of environment quality. Sections: powers for government to issue directions, establish standards, zone regulations. Punishment: fine/imprisonment. Applies nationwide.", cat: "environment" },
  { q: "Explain Forest Conservation Act 1972", a: "Regulates forest diversion for non-forest use. Prior central approval required. 2/3 forest diverted for non-forest purpose requires national approval. Rehabilitation mandatory. Afforestation requirement.", cat: "environment" },
  { q: "What is the Wildlife Protection Act 1972?", a: "Protects wildlife, establishes national parks (243), wildlife sanctuaries (100+). Schedule I-VI species have varying protections. Hunting prohibition, penalties severe. Tiger Project 1973.", cat: "environment" },
  { q: "Define the Water Pollution Control Act 1974", a: "Prevents water pollution. Water Quality Board established. Standards for industrial effluent, municipal waste. Penalties: 5 lakh + 3 years imprisonment. Applies to surface/groundwater.", cat: "environment" },
  { q: "Explain the Air Quality Act 1981", a: "Prevents air pollution. Air Quality Standards set. Industries must comply. Non-attainment zones identified (47+). Penalties similar to water act. Vehicle emission standards increased.", cat: "environment" },
  { q: "What is the NGT (National Green Tribunal) Act 2010?", a: "Independent judiciary for environmental disputes. Fast-track resolution. Benches: Delhi (principal), 7 regional. Jurisdiction: environmental laws. NGT orders enforceable. No appeal to HC on facts.", cat: "environment" },
  { q: "Define the Biological Diversity Act 2002", a: "Regulates conservation, sustainable use of biodiversity. Establishes Biodiversity Board. Access to biological resources controlled. Benefit-sharing from genetic resources. ABS principles implemented.", cat: "environment" },
  { q: "Explain CRZ Notification 2019 (Coastal Regulation Zone)", a: "Protects coastal ecosystems. Restricted development in coastal areas. CRZ I-IV categories. Fishing community rights balanced with conservation. Committee approval for activities.", cat: "environment" },
  { q: "What is EIA (Environmental Impact Assessment)?", a: "2006 notification: mandatory before projects (mining, thermal, hydro, highways). Category A (national), B (state) level approval. Screening, scoping, baseline studies required.", cat: "environment" },
  { q: "Explain Paris Agreement 2015", a: "1.5Â°C warming limit target. NDCs: Nationally Determined Contributions. India's target: 40% non-fossil by 2030. Ratified 2016. Legally binding under UNFCCC.", cat: "environment" },
  { q: "What is the Kyoto Protocol?", a: "1997 treaty: binding GHG reduction targets. Industrialized nations: average 5% reduction. Mechanisms: carbon trading, clean development mechanism. India: non-Annex I (no binding targets).", cat: "environment" },
  { q: "Define Montreal Protocol 1987", a: "Protects ozone layer. Phase-out of CFCs, halons, methyl bromide. India signatory. Major success story. Global ozone recovery expected by 2070.", cat: "environment" },
  { q: "Explain Basel Convention 1989", a: "Controls hazardous waste trade. Export to developing countries restricted. Amendments: Basel Ban (1995) restricts hazardous waste export from OECD to non-OECD. India complies.", cat: "environment" },
  { q: "What is the Stockholm Convention 2001?", a: "Eliminates persistent organic pollutants (POPs). 12 chemicals initially listed (now 30+). India ratified 2006. DDT restricted, dioxins, furans controlled.", cat: "environment" },
  { q: "Define the Ramsar Convention 1971", a: "Wetlands conservation. 172 parties. India: 42 wetlands listed (Chilika, Sundarbans, Kashmir lakes). Montreux record for threatened wetlands. Designation brings international support.", cat: "environment" },
  { q: "Explain CITES (Convention on International Trade in Endangered Species) 1973", a: "Controls trade in endangered species. Appendix I (prohibited), II (regulated), III (monitored). India: 250+ species protected (Bengal tiger, Asian elephant, rhinoceros).", cat: "environment" },
  { q: "What is the CBD (Convention on Biological Diversity) 1992?", a: "Conservation of biodiversity, sustainable use, genetic benefit-sharing. Nagoya Protocol (2014): ABS principles. India mega-biodiversity nation (7-8% global species). Ratified 1994.", cat: "environment" },
  { q: "Define the Bonn Convention 1979", a: "Migratory species conservation. 133 parties. India: 23 migratory species protected (cranes, flamingos, marine turtles). Bilateral/multilateral agreements supported.", cat: "environment" },
  { q: "Explain the Precautionary Principle", a: "Environmental law cornerstone: if activity hazardous, precautions mandatory even if cause-effect unproven. Burden on activity proponent to prove safety. Applied in NGT cases.", cat: "environment" },
  { q: "What is the Polluter Pays Principle?", a: "Polluter bears pollution cost (cleanup, compensation). Established in Rio Declaration 1992. Applied in India: industries must manage waste, liability clear.", cat: "environment" },
  { q: "Define Sustainable Development Principle", a: "Meeting current needs without compromising future generations. Triple bottom line: economic, social, environmental. Integrated into Indian constitutional jurisprudence via Article 21, 48.", cat: "environment" },
  { q: "Explain Intergenerational Equity Principle", a: "Present generation's duty to preserve environment for future. Articulated in Stockholm Principle 1. Applied in Subramanian Swamy v Union judgment (dam projects).", cat: "environment" },
  { q: "What are India's Protected Areas?", a: "243 national parks, 100+ wildlife sanctuaries, 50+ conservation reserves. Coverage: 5% land. Examples: Jim Corbett, Kaziranga, Great Himalayan. IUCN categories I-VI.", cat: "environment" },
  { q: "Explain Tiger Project 1973", a: "Operation Tiger: 9 tiger reserves initially, now 50+. Population: 3000+ (2022). Success in conservation management. Project Tiger funded by government, international support.", cat: "environment" },
  { q: "What is Project Elephant?", a: "Asian elephant conservation. 32 ranges. Population: 29,000+ (2017 census). Human-wildlife conflict management. Corridors created for migration. Poaching controlled.", cat: "environment" },
  { q: "Define Air Quality Index (AQI)", a: "Measures air quality: 0-50 Good, 50-100 Satisfactory, 100-200 Moderately Polluted, 200-300 Poor, 300-400 Very Poor, 400+ Severe. Delhi frequently crosses 400 in winters.", cat: "environment" },
  { q: "Explain Water Quality Standards", a: "pH, dissolved oxygen, turbidity, microbial counts monitored. Bureau of Indian Standards (BIS) sets limits. Supreme Court: drinking water fundamental right. Contamination: criminal liability.", cat: "environment" },
  { q: "What is Climate Action?", a: "India's NDC: 40% non-fossil electricity, 1 billion tonnes emissions reduction. Renewable target: 500 GW by 2030. Coal phase-down gradual. Green hydrogen push.", cat: "environment" },
  { q: "Explain Soil Conservation Measures", a: "Soil erosion control: terracing, contour bunding. Wasteland reclamation: 33 million hectares targeted. Desertification combat: arid area development schemes. Soil health card distribution.", cat: "environment" },
  { q: "What are NGT Landmark Judgments?", a: "Delhi pollution (2015): brick kilns closed. Coastal regulation (2015): Dabolim airport case. Coal ash: fly ash utilization mandated. Environmental compliance: closure orders effective.", cat: "environment" },
  { q: "Define Circular Economy Principles", a: "Reduce-Reuse-Recycle model. Extended Producer Responsibility (EPR) for plastic. Battery recycling mandated. Packaging material reuse promoted. Targets: zero waste by 2030.", cat: "environment" },
  { q: "Explain Renewable Energy Transition", a: "Solar power: cheapest generation (3 rupees/unit). Wind: capacity 45 GW. Grid stability challenges. Battery storage: lithium-ion costs declining. Green hydrogen emerging.", cat: "environment" },
  { q: "What is Marine Pollution Control?", a: "Coastal waters protection: industrial discharge regulation. Ship-breaking sites: Alang-Sosiya. Marine Protected Areas: 4 established. UNCLOS compliance for maritime zones.", cat: "environment" },
  { q: "Explain Noise Pollution Act", a: "Silent zones: courts, hospitals, schools. Residential area sound limits: 55 dB day, 45 dB night. Industrial areas: 75 dB. Firecrackers regulation: Diwali restrictions.", cat: "environment" },
  { q: "What is Environmental Audit?", a: "Mandatory for industries: pollution control compliance check. Annual reporting. Frequency: 2 years for large industries. Penalties for non-compliance: prosecution, closure.", cat: "environment" },
  { q: "Define Environmental Impact on Public Health", a: "Air pollution: respiratory disease mortality (1 million+ annually). Water contamination: waterborne diseases. Climate change: heat stress, disease vector expansion. Vulnerable populations: children, elderly, poor.", cat: "environment" },
  { q: "Explain Environmental Justice", a: "Disproportionate burden on marginalized communities: FRA 2006 protects forest dwellers, tribal rights. Pollution in poor areas: environmental racism. Remedy: environmental audits, compensation.", cat: "environment" },
  { q: "What is the Right to Healthy Environment?", a: "Not explicitly in Constitution but derived from Art 21 (life). Recognized in environmental judgments. Fundamental right status debated. Practical relief: PIL mechanism effective.", cat: "environment" },

  // INTERNATIONAL - 40 cards
  { q: "What is the United Nations (UN)?", a: "193 member states. Established 1945. Six organs: General Assembly, Security Council, ECOSOC, Secretariat, ICJ, Trusteeship Council. Headquarters: New York. Charter: international law foundation.", cat: "international" },
  { q: "Explain the UN Security Council", a: "15 members: 5 permanent (P5: USA, China, Russia, UK, France with veto), 10 non-permanent. Maintains international peace. Resolutions: mandatory for all states. Veto power controversial.", cat: "international" },
  { q: "What is the UN General Assembly?", a: "All 193 members, each with one vote. Debates, recommends on international issues. Non-binding resolutions. Annual sessions. India active participant, G77 leader.", cat: "international" },
  { q: "Define ICJ (International Court of Justice)", a: "UN's principal judicial organ. 15 judges. Cases: disputes between states, advisory opinions. Contentious cases: states agree jurisdiction. India: party to many cases (Kulbhushan Jadhav).", cat: "international" },
  { q: "Explain ICC (International Criminal Court)", a: "123 states parties. Prosecutes: genocide, crimes against humanity, war crimes. Individuals prosecuted. India: not member (concerned over sovereignty). Legitimacy questions post-Palestine judgments.", cat: "international" },
  { q: "What is the UNGA/UNSC?", a: "General Assembly: soft law (resolutions, declarations). Security Council: hard law (binding resolutions). Hierarchy: SC resolutions override GA on peace/security. Enforcement: SC can mandate military action.", cat: "international" },
  { q: "Define Specialized UN Agencies", a: "WHO: health. UNESCO: culture/education. UNHCR: refugees. UNEP: environment. UNEP on climate strong role. India: major contributor to most agencies.", cat: "international" },
  { q: "Explain ASEAN (Association of Southeast Asian Nations)", a: "10 members: Brunei, Cambodia, Indonesia, Laos, Malaysia, Myanmar, Philippines, Singapore, Thailand, Vietnam. Established 1967. ASEAN Regional Forum includes India. ASEAN+3 with China, Japan, Korea.", cat: "international" },
  { q: "What is the East Asia Summit?", a: "16 members: ASEAN+8 (USA, Russia, Japan, China, India, South Korea, Australia, New Zealand). Dialogue platform. Initiated by Indonesia 2005. Annual meetings.", cat: "international" },
  { q: "Define SAARC (South Asian Association for Regional Cooperation)", a: "8 members: Bangladesh, Bhutan, India, Maldives, Nepal, Pakistan, Sri Lanka, Afghanistan. Established 1985. Trade: 5% of total. Political tensions hamper progress.", cat: "international" },
  { q: "Explain BIMSTEC (Bay of Bengal Initiative)", a: "7 members: Bangladesh, Bhutan, India, Myanmar, Nepal, Sri Lanka, Thailand. Alternative to SAARC. Maritime cooperation focus. Proposed connecting Bangladesh-Bhutan-India-Myanmar-Sri Lanka-Thailand.", cat: "international" },
  { q: "What is SCO (Shanghai Cooperation Organization)?", a: "10 members: China, Russia, India, Pakistan, Kazakhstan, Kyrgyzstan, Tajikistan, Uzbekistan, Iran, Belarus. Founded 2001. Counter-terrorism focus. Energy security cooperation.", cat: "international" },
  { q: "Define BRICS", a: "Brazil, Russia, India, China, South Africa. Established 2009. Challenges Western dominance. NDB (New Development Bank) founded 2015. Expanded 2023: UAE, Egypt, Iran, Saudi Arabia. De-dollarization focus.", cat: "international" },
  { q: "Explain G20 (Group of 20)", a: "19 countries + EU. Largest economies (80% global GDP). Informal forum. India presidency 2023: development focus. 2024: Brazil presidency. Consensus-based.", cat: "international" },
  { q: "What is the QUAD (Quadrilateral Security Dialogue)?", a: "India, USA, Japan, Australia. Formed 2007, formalized 2017. Counters Chinese influence. Focuses: Indo-Pacific stability, democratic values, trade rules. Annual Quad summits.", cat: "international" },
  { q: "Define AUKUS", a: "Australia-UK-USA alliance 2021. Provides nuclear submarines to Australia. Concerned India but aligned with QUAD. China views as threat. Regional implications significant.", cat: "international" },
  { q: "Explain NATO (North Atlantic Treaty Organization)", a: "30 members: 29 European, Canada, USA. Founded 1949. Collective defense: Article 5. Intervention: Kosovo, Afghanistan, Libya. Recent: Sweden, Finland joined. China, Russia viewed as threats.", cat: "international" },
  { q: "What is the ICJ Statute?", a: "Constituent instrument of ICJ. Compulsory jurisdiction: optional. General jurisdiction: contentious cases between states. Advisory jurisdiction: UNGA/UNSC request. India: accepted with reservations.", cat: "international" },
  { q: "Explain WTO (World Trade Organization)", a: "164 members. Promotes free trade. Most Favored Nation (MFN) principle. Dispute Settlement Mechanism. India: major player, TRIPS waiver advocate. Doha round stalled.", cat: "international" },
  { q: "What is the IMF (International Monetary Fund)?", a: "190 members. Maintains monetary cooperation, exchange stability. Provides loans with conditions. Special Drawing Right (SDR): reserve currency. India: largest emerging market borrower historically.", cat: "international" },
  { q: "Define World Bank", a: "Group of 4 institutions: IBRD (loans to developing nations), IDA (poorest countries), IFC (private sector), MIGA (investment insurance). Governance: weighted voting. India borrower and contributor.", cat: "international" },
  { q: "Explain ADB (Asian Development Bank)", a: "56 member countries. Promotes development in Asia-Pacific. Loans, grants, technical assistance. Headquarters: Manila. India significant member, declining borrower due to growth.", cat: "international" },
  { q: "What is UNCLOS (United Nations Convention on Law of the Sea)?", a: "1982 treaty. 168 parties (USA not). Establishes maritime zones: territorial (12 nm), contiguous (24 nm), EEZ (200 nm), continental shelf. Dispute resolution mechanism. India: signatory, active role.", cat: "international" },
  { q: "Define the Convention on the Law of Treaties", a: "1969 Vienna Convention. Rules for treaty conclusion, interpretation, amendments. Good faith performance. Rebus sic stantibus: material change. India: signatory, applies in international relations.", cat: "international" },
  { q: "Explain International Humanitarian Law (IHL)", a: "Governs armed conflicts. Geneva Conventions (1949): protection of civilians, POWs. Additional Protocols (1977): protection intensified. War crimes prosecution under international law.", cat: "international" },
  { q: "What is the UDHR (Universal Declaration of Human Rights)?", a: "1948 declaration: 30 articles. First international human rights document. Not binding but foundational. India signatory. Criticized for Western bias, not enforceable.", cat: "international" },
  { q: "Explain ICCPR (International Covenant on Civil and Political Rights)", a: "1966 treaty: 172 parties. Binding document. Civil/political rights protected. Optional Protocol: individual complaints. India: signatory without protocol.", cat: "international" },
  { q: "Define ICESCR (International Covenant on Economic, Social, Cultural Rights)", a: "1966 treaty: 171 parties. Economic/social/cultural rights. Gradual implementation required. Less enforceable than ICCPR. India: signatory, implementing gradually.", cat: "international" },
  { q: "What is CEDAW (Convention on Elimination of Discrimination Against Women)?", a: "1979 treaty: 189 parties. Gender equality, women's rights. Optional Protocol: complaints mechanism. India: signatory with reservations (marriage, family law).", cat: "international" },
  { q: "Explain CRC (Convention on Rights of the Child)", a: "1989 treaty: 196 parties. 54 articles. Child protection: welfare, education, protection from exploitation. Most ratified human rights treaty. India: signatory, implementation mixed.", cat: "international" },
  { q: "What is Refugee Law?", a: "1951 Refugee Convention. 4.5 million refugees globally. Non-refoulement: cannot return to persecution. India: large refugee population (Myanmar, Afghan, Rohingya). Not convention signatory.", cat: "international" },
  { q: "Define Universal Jurisdiction", a: "Crimes against humanity prosecutable anywhere. Genocide, torture, war crimes. Example: Pinochet trial. Controversial: sovereignty implications. India cautious on adoption.", cat: "international" },
  { q: "Explain Extradition Laws", a: "Treaty-based: bilateral/multilateral agreements. India: 59 countries. Exceptions: political offenses, national interest. Dual criminality required. KYM case: KYM extradited to India.", cat: "international" },
  { q: "What is Sovereign Immunity?", a: "State cannot be sued in another state's court. Foreign Sovereign Immunities Act: limited exceptions. Functional immunity: official acts protected. Absolute vs restrictive immunity.", cat: "international" },
  { q: "Define International Arbitration", a: "Private dispute resolution. UNCITRAL rules. Binding awards. Enforcement: New York Convention (172 parties). India signatory. ICC, LCIA, SIAC common forums.", cat: "international" },
  { q: "Explain Diplomatic Immunity", a: "Vienna Convention 1961: diplomats protected from criminal prosecution. Family members partially covered. Waivable by sending state. Exceptions: personal injury cases rarely. Indian diplomats protected abroad.", cat: "international" },
  { q: "What is the Legality of Nuclear Weapons?", a: "ICJ advisory opinion 1996: use generally prohibited unless existential threat. India: declared nuclear power 1998. NPT non-signatory. CTBT signed, not ratified. MAD doctrine informally.", cat: "international" },
  { q: "Define Cybersecurity International Law", a: "Tallinn Manual: NATO perspective on cyber warfare. Attribution difficult. Sovereignty implications. India: cyberattacks attributed to state actors. UN working group on norms.", cat: "international" },
  { q: "Explain International Environmental Law", a: "Rio Declaration 1992: sustainable development. Paris Agreement: climate action binding. CBD: biodiversity conservation. India: active participant, climate justice advocate.", cat: "international" },
  { q: "What is the Hague Convention?", a: "Multiple conventions: Laws of War (1907), Civil Procedure (1954), Jurisdiction (1968). India signatory to several. Governs cross-border litigation, international contracts.", cat: "international" },

  // HISTORY - 30 cards
  { q: "What is the Regulating Act of 1773?", a: "First legislation to regulate East India Company's Indian governance. Established Bengal Presidency. Appointed Governor-General (Warren Hastings). Created Supreme Court Calcutta (1774). Foundation of Company control.", cat: "history" },
  { q: "Explain Pitt's India Act 1784", a: "Reformed Company governance. Established Board of Control under Crown. Separated commercial/political functions. Governor-General's authority clarified. Centralized Company control.", cat: "history" },
  { q: "What are Charter Acts (1793, 1813, 1833, 1853)?", a: "1793: regulation of company. 1813: opened trade, allowed missionaries. 1833: abolished company's commercial functions, Governor-General over all territories. 1853: open competition for civil service introduced.", cat: "history" },
  { q: "Define the Government of India Act 1858", a: "Transferred Company control to Crown. Viceroy appointed (Crown representative). Secretary of State for India. Bureaucratic system formalized. British Raj began.", cat: "history" },
  { q: "Explain the Government of India Act 1909 (Morley-Minto Reforms)", a: "Limited Indian representation in Legislative Councils. Expanded local/provincial councils. Created separate Muslim electorate. Communal representation introduced (controversial).", cat: "history" },
  { q: "What is the Government of India Act 1919 (Montagu-Chelmsford)?", a: "Introduced dyarchy: elected councils with limited powers, executive retained control. Provincial autonomy increased. Responsible government concept introduced. Entry for elected Indians.", cat: "history" },
  { q: "Explain the Government of India Act 1935", a: "Most comprehensive till 1947. Federal structure proposed (not fully implemented). Provincial autonomy granted. Dyarchy replaced with responsible government in provinces. Reserved/general constituencies.", cat: "history" },
  { q: "What is the Constituent Assembly?", a: "Established December 1946. 389 members. Drafted Constitution. Led by BR Ambedkar (Chairman Drafting Committee). Dr. Rajendra Prasad (President). Took 2 years 11 months 18 days.", cat: "history" },
  { q: "Explain the Cabinet Mission Plan 1946", a: "Three British ministers: Pethick-Lawrence, Cripps, Alexander. Proposed federal structure. Negotiations with Congress, Muslim League. Failed due to League's Pakistan demand. Communal tensions escalated.", cat: "history" },
  { q: "What is Cripps Mission 1942?", a: "Stafford Cripps sent to negotiate with Indian leaders. Offered Dominion Status post-WWII. Rejected by Congress (immediate independence wanted). India demanded entry into planning. Quit India movement followed.", cat: "history" },
  { q: "Explain Simon Commission 1927-1929", a: "British commission (no Indian members). Recommended responsible government in provinces. Rejected by Congress due to lack of Indian representation. Civil disobedience followed. Boycotted by Indian leaders.", cat: "history" },
  { q: "What is the Indian Independence Act 1947?", a: "Partitioned India into India/Pakistan. August 15, 1947: independence date. Dominion status until republic (1950). Boundaries decided by Radcliffe Line. 10 million refugees.", cat: "history" },
  { q: "Explain the First Amendment to Constitution", a: "1951: added 9th Schedule (protected laws), imposed restrictions on Art 19 (freedom). Allowed agrarian reform (land ceiling laws). Upheld Zamindari abolition. Challenged basic rights concept.", cat: "history" },
  { q: "What was India's First Supreme Court Case?", a: "Dalmia v Commissioner of Income Tax (1958): PIL jurisdiction established. Supreme Court's role in protecting rights defined. Foundation for later activism.", cat: "history" },
  { q: "Explain the Abolition of Sati Act 1829", a: "Declared sati (widow immolation) illegal. Governor-General William Bentinck. Criminalized practice. Religious opposition overcome. Progressive reform, criticized as cultural imperialism.", cat: "history" },
  { q: "What is the Age of Consent Act 1860/1891?", a: "Criminalized child marriage. Age raised from 10 to 12 (1860), then 18 (1891). Aimed at child protection. Social reform movement success. Implementation initially weak.", cat: "history" },
  { q: "Explain the Bengal Renaissance (18th-19th century)", a: "Social-intellectual movement. Ram Mohan Roy, Keshab Chandra Sen. Challenged practices: sati, caste. Promoted education, reform. Foundation of modern Indian thought, nationalism.", cat: "history" },
  { q: "What is the Indian National Congress?", a: "Founded 1885 (A.O. Hume). First all-India political organization. Advocacy for representative government. Shifted from moderate (Gokhale) to extremist (Tilak) to revolutionary approaches.", cat: "history" },
  { q: "Explain the Drain of Wealth Theory", a: "Dadabhai Naoroji articulated: British rule drained India's wealth via taxes, trade imbalances. Economic exploitation justified nationalist sentiment. Foundation of economic grievance against colonialism.", cat: "history" },
  { q: "What are the First Information Report (FIR) origins?", a: "Established under CrPC 1898 (now BNSS 2023). Police obligation to record offense. Provides accused notice. Investigator's guiding document. Procedural safeguard for rights.", cat: "history" },
  { q: "Explain the Quit India Movement 1942", a: "Gandhi's call: 'Do or Die'. Mass civil disobedience. Arrests of Congress leaders. Student, worker participation. Accelerated independence negotiations. Last major mass movement under British.", cat: "history" },
  { q: "What is the Salt March 1930?", a: "Gandhi's civil disobedience against salt tax. 240 miles walk to coastal areas. Mass participation. Broke salt monopoly law. Symbol of nationalist defiance.", cat: "history" },
  { q: "Explain Constitutional Evolution Timeline", a: "Regulating Act 1773 â Pitt's India Act 1784 â Charter Acts (1793-1853) â GoI Act 1858 â GoI Act 1909 â GoI Act 1919 â GoI Act 1935 â Indian Independence Act 1947 â Constitution 1950.", cat: "history" },
  { q: "What is Dalit History?", a: "Ambedkar's conversion 1956: Buddhism adoption. Annihilation of Caste doctrine. Constitutional protections (SCs/STs). Reservations policy. Ongoing discrimination despite legal framework.", cat: "history" },
  { q: "Explain the State Integration Process (1947-1956)", a: "Integration of 565 princely states into Union. Sardar Vallabhbhai Patel's leadership. Incentives, persuasion, military action if needed. Merger agreements signed. National cohesion achieved.", cat: "history" },
  { q: "What is the Zamindari Abolition?", a: "Abolished feudal landlord system post-independence. Zamindars lost intermediary role. Direct cultivator-state relationship. Land redistribution to tillers. 1st Amendment protected these laws.", cat: "history" },
  { q: "Explain Medieval Indian Legal Systems", a: "Hindu Law: Manusmriti, Yajnavalkya Smriti. Islamic Law: Sharia. British overlay: common law. Syncretic system post-1858. Codification of laws undertaken.", cat: "history" },
  { q: "What is the Impact of British Common Law on India?", a: "Contract law codified (1872). Evidence Act 1872. Criminal procedure standardized. Courts hierarchically organized. Supreme Court established. Jury system introduced (later modified).", cat: "history" },
  { q: "Explain the Transformation of Indian Society (1800-1947)", a: "British education system introduction. English language dominance. Urbanization acceleration. Industrial disruption of traditional economy. Social reform movements. Nationalist consciousness emergence.", cat: "history" },
  { q: "What is the Constitutional Safeguards History?", a: "Fundamental Rights inspired by USA Constitution. DPSP from Irish Constitution. Amendments process unique. Basic structure doctrine evolved 1973. Judiciary activism grew post-1970s.", cat: "history" },
];

